INSERT INTO `articles` VALUES (1,1,1,'Menjaga Kesehatan Ibu dan Anak: Peran Posyandu dalam Masyarakat',NULL,'<p>Pelayanan rutin Posyandu terus ditingkatkan untuk memastikan tumbuh kembang anak yang optimal dan kesehatan ibu yang terjaga. Melalui berbagai program seperti imunisasi, pemberian vitamin, dan edukasi gizi, Posyandu menjadi garda terdepan dalam menciptakan generasi yang sehat dan kuat.</p><p>Pemeriksaan rutin setiap bulan sangat penting untuk memantau perkembangan berat badan dan tinggi badan anak, serta memberikan konseling gizi kepada para ibu.</p>',NULL,NULL,'menjaga-kesehatan-ibu-dan-anak','published','2026-07-08 02:39:22','2026-07-08 02:39:22','2026-07-08 02:39:22'),(2,1,2,'Menu Sehat Pendamping ASI (MPASI) Terbaik',NULL,'<p>Panduan gizi penting selama masa kehamilan agar ibu dan janin tetap sehat dan bertenaga sepanjang hari. MPASI yang sehat harus mengandung nutrisi makro dan mikro yang seimbang, mulai dari karbohidrat, protein hewani, hingga lemak sehat.</p>',NULL,NULL,'menu-sehat-mpasi-terbaik','published','2026-07-07 02:39:22','2026-07-08 02:39:22','2026-07-08 02:39:22'),(3,1,3,'Pentingnya Imunisasi Dasar Lengkap',NULL,'<p>Imunisasi adalah cara terbaik untuk melindungi anak dari berbagai penyakit berbahaya yang dapat dicegah. Pastikan anak Anda mendapatkan jadwal imunisasi yang lengkap sesuai anjuran tenaga kesehatan di Posyandu terdekat.</p>',NULL,NULL,'pentingnya-imunisasi-dasar-lengkap','published','2026-07-06 02:39:22','2026-07-08 02:39:22','2026-07-08 02:39:22'),(4,1,3,'Tips Kesehatan Keluarga Bagian 1',NULL,'<p>Ini adalah artikel edukasi kesehatan untuk memberikan wawasan lebih mendalam tentang pola hidup sehat di lingkungan keluarga.</p>',NULL,NULL,'tips-kesehatan-keluarga-1','published','2026-07-05 02:39:22','2026-07-08 02:39:22','2026-07-08 02:39:22'),(5,1,2,'Tips Kesehatan Keluarga Bagian 2',NULL,'<p>Ini adalah artikel edukasi kesehatan untuk memberikan wawasan lebih mendalam tentang pola hidup sehat di lingkungan keluarga.</p>',NULL,NULL,'tips-kesehatan-keluarga-2','published','2026-07-04 02:39:22','2026-07-08 02:39:22','2026-07-08 02:39:22'),(6,1,4,'Tips Kesehatan Keluarga Bagian 3',NULL,'<p>Ini adalah artikel edukasi kesehatan untuk memberikan wawasan lebih mendalam tentang pola hidup sehat di lingkungan keluarga.</p>',NULL,NULL,'tips-kesehatan-keluarga-3','published','2026-07-03 02:39:22','2026-07-08 02:39:22','2026-07-08 02:39:22'),(7,1,3,'Tips Kesehatan Keluarga Bagian 4',NULL,'<p>Ini adalah artikel edukasi kesehatan untuk memberikan wawasan lebih mendalam tentang pola hidup sehat di lingkungan keluarga.</p>',NULL,NULL,'tips-kesehatan-keluarga-4','published','2026-07-02 02:39:22','2026-07-08 02:39:22','2026-07-08 02:39:22'),(8,1,3,'Tips Kesehatan Keluarga Bagian 5',NULL,'<p>Ini adalah artikel edukasi kesehatan untuk memberikan wawasan lebih mendalam tentang pola hidup sehat di lingkungan keluarga.</p>',NULL,NULL,'tips-kesehatan-keluarga-5','published','2026-07-01 02:39:22','2026-07-08 02:39:22','2026-07-08 02:39:22'),(9,1,2,'Tips Kesehatan Keluarga Bagian 6',NULL,'<p>Ini adalah artikel edukasi kesehatan untuk memberikan wawasan lebih mendalam tentang pola hidup sehat di lingkungan keluarga.</p>',NULL,NULL,'tips-kesehatan-keluarga-6','published','2026-06-30 02:39:22','2026-07-08 02:39:22','2026-07-08 02:39:22');
